    ["lib/libcrypto/CA"] = {
        ["custom"] = true,
        ["dynamic_vars"] = {},
        ["has_makefile"] = true,
        ["has_regress_targets_var"] = true,
        ["ldadd_libs"] = {},
        ["progs"] = {},
        ["srcs"] = {},
        ["targets"] = {
            ["run-verify-client"] = {
                ["recipe_lines"] = {
                    "openssl verify -purpose sslclient -CAfile chain.pem client.cert.pem",
                },
            },
            ["run-verify-intermediate"] = {
                ["recipe_lines"] = {
                    "openssl verify -CAfile root.cert.pem intermediate.cert.pem",
                    "chain.pem: intermediate.cert.pem root.cert.pem",
                    "cat intermediate.cert.pem root.cert.pem > chain.pem",
                    "server.key.pem: stamp-clean",
                    "openssl genrsa -out server.key.pem 2048",
                    "server.csr.pem: intermediate.cnf server.key.pem",
                    "openssl req -batch -config ${.CURDIR}/intermediate.cnf -new -sha256  \9    -subj '/CN=server.openbsd.org/OU=So and Sos/O=OpenBSD/C=CA'  \9    -key server.key.pem -out server.csr.pem",
                    "server.cert.pem: intermediate.cnf intermediate.cert.pem server.csr.pem",
                    "openssl ca -batch -config ${.CURDIR}/intermediate.cnf  \9    -extensions server_cert -days 5 -notext -md sha256  \9    -in server.csr.pem -out server.cert.pem",
                    "client.key.pem: stamp-clean",
                    "openssl genrsa -out client.key.pem 2048",
                    "client.csr.pem: intermediate.cnf intermediate.cert.pem client.key.pem",
                    "openssl req -batch -config ${.CURDIR}/intermediate.cnf -new -sha256  \9    -subj '/CN=client/OU=So and Sos/O=OpenBSD/C=CA'  \9    -key client.key.pem -out client.csr.pem",
                    "client.cert.pem: intermediate.cnf intermediate.cert.pem client.csr.pem",
                    "openssl ca -batch -config ${.CURDIR}/intermediate.cnf  \9    -extensions usr_cert -days 5 -notext -md sha256  \9    -in client.csr.pem -out client.cert.pem",
                },
            },
            ["run-verify-server"] = {
                ["recipe_lines"] = {
                    "openssl verify -purpose sslserver -CAfile chain.pem server.cert.pem",
                },
            },
        },
        ["unknown_includes"] = {},
    },
