    ["sbin/bioctl"] = {
        ["custom"] = true,
        ["dynamic_vars"] = {},
        ["has_makefile"] = true,
        ["has_regress_targets_var"] = true,
        ["ldadd_libs"] = {},
        ["progs"] = {},
        ["srcs"] = {},
        ["targets"] = {
            ["cleanup"] = {
                ["recipe_lines"] = {
                    "${SUDO} vnconfig  -u -- \"$$(<${CHUNKDEVFILE})\" 2>/dev/null",
                },
            },
            ["create-chunk"] = {
                ["recipe_lines"] = {
                    "dd if=/dev/zero of=${CHUNKFILE} bs=512k count=0 seek=1 status=none",
                    "${SUDO} vnconfig -- ${CHUNKFILE} 1>${CHUNKDEVFILE}",
                    "echo 'RAID *' | ${SUDO} disklabel -wAT- -- \"$$(<${CHUNKDEVFILE})\"",
                },
            },
            ["create-passfile"] = {
                ["recipe_lines"] = {
                    "${SUDO} install -o root -m u=rw,go= /dev/null ${PASSFILE}",
                    "printf '%s\\n' '${OLDPW}' | ${SUDO} tee ${PASSFILE} 1>/dev/null",
                },
            },
            ["detach-volume"] = {
                ["recipe_lines"] = {
                    "${SUDO} ${BIOCTL} -d -- \"$$(<${VOLDEVFILE})\" 2>/dev/null",
                },
            },
            ["reopen-volume-with-passfile"] = {
                ["recipe_lines"] = {
                    "${SUDO} ${BIOCTL} -p${PASSFILE} -cC -l\"$$(<${CHUNKDEVFILE})a\" -- softraid0 |  \9\9grep -o 'sd[0-9]*$$' 1>${VOLDEVFILE}",
                },
            },
            ["reuse-active-chunk"] = {
                ["recipe_lines"] = {
                    "${SUDO} ${BIOCTL} -cC -l\"$$(<${CHUNKDEVFILE})a\" -- softraid0",
                },
            },
            ["scripted-change-passphrase"] = {
                ["recipe_lines"] = {
                    "printf '%s\\n%s\\n' '${OLDPW}' '${NEWPW}' |  \9\9${SUDO} ${BIOCTL} -s -P -v -- \"$$(<${VOLDEVFILE})\" |  \9\9tee -- ${ROUNDSFILE}",
                },
            },
            ["scripted-create-volume"] = {
                ["recipe_lines"] = {
                    "printf '%s\\n' '${OLDPW}' |  \9\9${SUDO} ${BIOCTL} -s -cC -l\"$$(<${CHUNKDEVFILE})a\" -- softraid0 |  \9\9grep -o 'sd[0-9]*$$' 1>${VOLDEVFILE}",
                },
            },
            ["scripted-recreate-volume"] = {
                ["recipe_lines"] = {
                    "printf '%s\\n' '${OLDPW}' |  \9\9${SUDO} ${BIOCTL} -s -Cforce -r${NROUNDS} -cC -l\"$$(<${CHUNKDEVFILE})a\" -- softraid0 |  \9\9grep -o 'sd[0-9]*$$' 1>${VOLDEVFILE}",
                },
            },
            ["set-empty-passphrase"] = {
                ["recipe_lines"] = {
                    "printf '\\n' | ${SUDO} ${BIOCTL} -s -P -- \"$$(<${VOLDEVFILE})\"",
                },
            },
            ["use-foreign-passfile"] = {
                ["recipe_lines"] = {
                    "${SUDO} chown build ${PASSFILE}",
                    "${SUDO} ${BIOCTL} -p${PASSFILE} -P -- \"$$(<${VOLDEVFILE})\"",
                },
            },
            ["use-public-passfile"] = {
                ["recipe_lines"] = {
                    "${SUDO} chmod a=rwx ${PASSFILE}",
                    "${SUDO} ${BIOCTL} -p${PASSFILE} -P -- \"$$(<${VOLDEVFILE})\"",
                },
            },
            ["verify-increased-rounds"] = {
                ["recipe_lines"] = {
                    "awk -safe -vOLD=${NROUNDS} -- ' \9\9NR == 1 { old = $$7 };  \9\9NR == 2 { new = $$7 };  \9\9END     { exit !(OLD == old && old <= new) }' ${ROUNDSFILE}",
                },
            },
        },
        ["unknown_includes"] = {},
    },
