                    "/sbin/ifconfig ${ETHER_IF} >ifconfig.out",
                    "grep 'inet ${ETHER_NET}.1 ' ifconfig.out",
                    "grep -c 'inet ' ifconfig.out | grep -q 1",
                },
            },
            ["run-ether-alias-host"] = {
                ["recipe_lines"] = {
                    "${IFCONFIG} ${ETHER_IF} ${ETHER_NET}.1/24",
