                    "${SETUP_START}",
                    "flowtype=esp; ${TEST_FLOWS}; if [[ $$_ret -ne 1 ]]; then exit 1; fi",
                    "${TEST_PING}; if [[ $$_ret -ne 1 ]]; then exit 1; fi",
