            ["run-intermediate-fail"] = {
                ["recipe_lines"] = {
                    "leftid=left-from-intermediate-from-ca-none;  \9rightid=right-from-intermediate-from-ca-none;  \9    ${SETUP_CONFIGS}",
                    "${SETUP_START}",
