            ["run-singleikesa"] = {
                ["recipe_lines"] = {
                    "flowtype=esp;  \9singleikesa=true;  \9leftid=left-from-ca-both;  \9rightid=right-from-ca-both;  \9    ${SETUP_CONFIGS}",
                    "${SETUP_START}",
                    "sleep 1; ${SETUP_RELOAD_RIGHT};  \9sleep 3; ${TEST_SINGLEIKESA}",
