                ["recipe_lines"] = {
                    "flowtype=esp;  \9leftid=left-from-ca-both;  \9rightid=right-from-ca-both;  \9    side=left; srcid=$$leftid; local=${LEFT_ADDR}; peer=${RIGHT_ADDR};  \9    dstid=\"dstid $$rightid\";  \9    ${SETUP_CONFIG};  \9    side=right; mode=passive; srcid=\"borked\"; local=${RIGHT_ADDR};  \9    peer=${LEFT_ADDR}; dstid=\"\";  \9    ${SETUP_CONFIG};  \9    srcid=$$rightid;  \9    ${SETUP_CONFIG};  \9    srcid=\"roflol\";  \9    ${SETUP_CONFIG};  \9    ${DEPLOY_CONFIGS}",
