            ["run-transport"] = {
                ["recipe_lines"] = {
                    "flowtype=esp;  \9tmode=transport;  \9leftid=left-from-ca-both;  \9rightid=right-from-ca-both;  \9    ${SETUP_CONFIGS}",
                    "${SETUP_START}",
                    "tmode=transport; flowtype=esp;  \9    ${TEST_FLOWS}; if [[ $$_ret -ne 0 ]]; then exit 1; fi",
                    "${TEST_PING}; if [[ $$_ret -ne 0 ]]; then exit 1; fi",
                },
            },
            ["run-udpencap-port"] = {
                ["recipe_lines"] = {
                    "flowtype=esp;  \9leftid=left-from-ca-both;  \9rightid=right-from-ca-both;  \9    ${SETUP_CONFIGS};  \9sysctl=\"net.inet.esp.udpencap_port=9999\";  \9    ${SETUP_SYSCTL};",
                    "iked_flags=-p9999;  \9    ${SETUP_START};",
                    "flowtype=esp; ${TEST_FLOWS}; if [[ $$_ret -ne 0 ]]; then exit 1; fi",
