            ["setup"] = {
                ["recipe_lines"] = {
                    ".PHONY: setup_certs",
                },
            },
            ["setup_certs"] = {
                ["recipe_lines"] = {
                    "echo \"cd /etc/iked\\n  \9    put left-from-ca-both.crt certs\\n  \9    put left-from-ca-right.crt certs\\n  \9    put left-from-ca-none.crt certs\\n  \9    put left-from-intermediate-from-ca-none.crt certs\\n  \9    put right-from-ca-none.crt certs\\n  \9    put left.key private/local.key\\n  \9    put intermediate-from-ca-none.crt ca\\n  \9    put ca-left.crt ca\\n  \9    put ca-both.crt ca\\n\" | sftp ${LEFT_SSH} -q;  \9echo \"cd /etc/iked\\n  \9    put right-from-ca-both.crt certs\\n  \9    put right-from-ca-left.crt certs\\n  \9    put right-from-ca-none.crt certs\\n  \9    put right-from-intermediate-from-ca-none.crt certs\\n  \9    put left-from-ca-none.crt certs\\n  \9    put right.key private/local.key\\n  \9    put intermediate-from-ca-none.crt ca\\n  \9    put ca-right.crt ca\\n  \9    put ca-both.crt ca\\n\" | sftp ${RIGHT_SSH} -q;  \9ssh ${LEFT_SSH} \"openssl rsa -in /etc/iked/private/local.key -pubout > /etc/iked/local.pub\";  \9ssh ${RIGHT_SSH} \"openssl rsa -in /etc/iked/private/local.key -pubout > /etc/iked/local.pub\"",
                },
            },
            ["setup_pf"] = {
                ["recipe_lines"] = {
                    "echo \"cd /tmp\\nput ${.CURDIR}/pf.in pf.conf\" | sftp -q ${LEFT_SSH}",
                    "echo \"cd /tmp\\nput ${.CURDIR}/pf.in pf.conf\" | sftp -q ${RIGHT_SSH}",
                    "-ssh ${LEFT_SSH} \"pfctl -f /tmp/pf.conf; pfctl -e\"",
                    "-ssh ${RIGHT_SSH} \"pfctl -f /tmp/pf.conf; pfctl -e\"",
                },
            },
            ["test_flows"] = {
                ["recipe_lines"] = {
                    "${TEST_FLOWS}",
                    "left.key right.key:",
                    "openssl genrsa -out $@ 2048",
                    "ca-both.crt ca-both.key:",
                    "caname=ca-both; ${SETUP_CA}",
                    "left-from-ca-both.crt: ca-both.crt ca-both.key left.key",
                    "caname=ca-both; name=left; ${SETUP_CERT}",
                    "right-from-ca-both.crt: ca-both.crt ca-both.key right.key",
                    "caname=ca-both; name=right; ${SETUP_CERT}",
                    "ca-left.crt ca-left.key:",
