            ["nfs"] = {
                ["recipe_lines"] = {
                    "grep '/mnt/regress-nfs-server\\>' /etc/exports ||  \9    echo /mnt/regress-nfs-server -maproot=0:0 127.0.0.1 >>/etc/exports",
                    "rcctl -f start portmap",
                    "rcctl -f start nfsd",
                    "rcctl -f start mountd",
