                    "mkdir /mnt/regress-mount/b",
                    "mount /dev/$$(<vnd)b /mnt/regress-mount/b",
                    "f=/mnt/regress-mount; for p in d e f g h i j k l m n o p; \9    do f=$$f/$$p; mkdir $$f; mount /dev/$$(<vnd)$$p $$f; done",
                    "mount",
                },
            },
            ["remove-diskimage"] = {
                ["recipe_lines"] = {
                    "rm -f diskimage",
                },
            },
            ["run-readonly-busy"] = {
                ["recipe_lines"] = {
                    "cp -r /usr /mnt/regress-mount &",
                    "sleep 5",
                    "sync",
                    "sleep 10",
                    "rm -rf /mnt/regress-mount/usr &",
                    "sleep .1",
                    "mount -f -ur /mnt/regress-mount",
                    "for i in `jot 20`; do  \9    pgrep -xf 'cp -r /usr' ||  \9    pgrep -xf 'rm -rf /mnt/regress-mount/usr' ||  \9    break; sleep 1; done",
                    "umount /mnt/regress-mount",
                    "fsck -y /dev/r$$(<vnd)a 2>&1 | tee fsck-clean.log",
                    "fsck -f -y /dev/r$$(<vnd)a 2>&1 | tee fsck-force.log",
                },
            },
            ["run-readonly-dangling"] = {
                ["recipe_lines"] = {
                    "touch /mnt/regress-mount/file",
                    "sleep 73 </mnt/regress-mount/file &",
                    "sleep .1",
                    "rm /mnt/regress-mount/file",
                    "mount -ur /mnt/regress-mount",
                    "pkill -xf 'sleep 73'",
                    "sleep .1",
                    "umount /mnt/regress-mount",
                    "fsck -y /dev/r$$(<vnd)a 2>&1 | tee fsck-clean.log",
                    "fsck -f -y /dev/r$$(<vnd)a 2>&1 | tee fsck-force.log",
                    "egrep -q 'yes|FILE SYSTEM WAS MODIFIED|MARKING FILE SYSTEM CLEAN'  \9    fsck-clean.log fsck-force.log",
                },
            },
            ["run-unmount-busy"] = {
                ["recipe_lines"] = {
                    "cp -r /usr /mnt/regress-mount &",
                    "sleep 5",
                    "sync",
                    "sleep 10",
                    "rm -rf /mnt/regress-mount/usr &",
                    "sleep .1",
                    "umount -f /mnt/regress-mount",
                    "fsck -y /dev/r$$(<vnd)a 2>&1 | tee fsck-clean.log",
                    "fsck -f -y /dev/r$$(<vnd)a 2>&1 | tee fsck-force.log",
                    "egrep -q 'File system is clean'  \9    fsck-clean.log",
                    "run-readonly-busy run-readonly-dangling:",
                    "@echo DISABLED",
                },
            },
            ["run-unmount-nested"] = {
                ["recipe_lines"] = {
                    "umount -f /mnt/regress-mount",
                    "mount",
                },
            },
            ["unconfig"] = {
                ["recipe_lines"] = {
                    "-umount -f /dev/$$(<vnd)a 2>/dev/null || true",
                    "-rmdir /mnt/regress-mount 2>/dev/null || true",
                    "-vnconfig -u $$(<vnd) 2>/dev/null || true",
                },
            },
        },
        ["unknown_includes"] = {},
    },
