        ["targets"] = {
            ["remote-setup"] = {
                ["recipe_lines"] = {
                    "ssh ${REMOTE_SSH} 'cd ${.CURDIR} && make copy splice'",
                    ".for p in tcp udp",
                    ".for r in copy splice",
                    "run-$p-$r: $r remote-setup",
                    "-pkill -x tcpbench",
                    "./$r ${p:S/tcp//:S/udp/-u/} -4 12345 127.0.0.1 12346 &  \9rpid=$$! ;  \9tcpbench ${p:S/tcp//:S/udp/-u/} -4 -t 7 -s -p 12346 &  \9sleep 1 ;  \9tcpbench ${p:S/tcp//:S/udp/-u/} -4 -t 5 127.0.0.1 ;  \9kill $$rpid ;  \9pkill -x tcpbench",
                    "sleep 1",
                    "remote-$p-$r: $r",
                    "-pkill -x $r",
                    "./$r ${p:S/tcp//:S/udp/-u/} -b ${REMOTE_ADDR} 12345 ${LOCAL_ADDR} 12346 &  \9rpid=$$! ;  \9sleep 10 ;  \9kill $$rpid",
                    ".endfor",
                    ".endfor",
                },
            },
        },
        ["unknown_includes"] = {},
