                    "${SUDO} /sbin/ifconfig lo$n inet6 ${SRC_TUNNEL6_$n} alias",
                    "${SUDO} /sbin/route -n -T $n add -inet -host ${DST_TUNNEL4_$n} 127.0.0.1",
                    "${SUDO} /sbin/route -n -T $n add -inet6 -host ${DST_TUNNEL6_$n} ::1",
                    "${SUDO} /sbin/ifconfig gif$n4 create rdomain $n tunneldomain $n",
                    "${SUDO} /sbin/ifconfig gif$n4 tunnel ${SRC_TUNNEL4_$n} ${DST_TUNNEL4_$n}",
                    "${SUDO} /sbin/ifconfig gif$n4 inet ${TUNNEL4_SRC_ADDR4_$n}/32 \9    ${TUNNEL4_DST_ADDR4_$n}",
                    "${SUDO} /sbin/ifconfig gif$n4 inet6 ${TUNNEL4_SRC_ADDR6_$n} \9    ${TUNNEL4_DST_ADDR6_$n}",
                    "${SUDO} /sbin/ifconfig gif$n6 create rdomain $n tunneldomain $n",
                    "${SUDO} /sbin/ifconfig gif$n6 tunnel ${SRC_TUNNEL6_$n} \9    ${DST_TUNNEL6_$n}",
                    "${SUDO} /sbin/ifconfig gif$n6 inet ${TUNNEL6_SRC_ADDR4_$n}/32 \9    ${TUNNEL6_DST_ADDR4_$n}",
                    "${SUDO} /sbin/ifconfig gif$n6 inet6 ${TUNNEL6_SRC_ADDR6_$n} \9    ${TUNNEL6_DST_ADDR6_$n}",
                    ".endfor",
                    "for i in `jot 50`; do \9    if ! { /sbin/ifconfig lo${N1}; /sbin/ifconfig lo${N2}; \9\9/sbin/ifconfig gif${N1}4; /sbin/ifconfig gif${N1}6; \9\9/sbin/ifconfig gif${N2}4; /sbin/ifconfig gif${N2}6; } \9\9| fgrep -q tentative; then \9\9    break; \9    fi; \9    sleep .1; \9done",
                },
