            ["run-netstat6"] = {
                ["recipe_lines"] = {
                    "awk 'BEGIN{ mpath = used = uses = max = 0; } \9    /^fc00::${N1}:0:0 /{ \9\9if ($$3 == \"UGHSBP\") mpath++; \9\9if ($$5 > 0) used++; \9\9if ($$5 > max) max = $$5; \9\9uses += $$5; \9    } \9    END{ \9\9print \"mpath \"mpath\", uses \"uses\", max \"max\", used \"used; \9\9if (mpath != 100) { print \"not 100 mpath: \" mpath; exit 1; } \9\9if (uses != 100) { print \"not 100 uses: \" uses; exit 1; } \9\9if (max > 30) { print \"max more than 30: \" max; exit 1; } \9\9if (used < 50) { print \"used less than 50: \" used; exit 1; } \9    }'  \9    netstat6.log",
