        ["targets"] = {
            ["busy-rdomains"] = {
                ["recipe_lines"] = {
                    ".for n in ${NUMS}",
                    "@if /sbin/ifconfig | grep -v '^lo$n:' | grep ' rdomain $n '; then \9    echo routing domain $n is already used >&2; exit 1; fi",
                    ".endfor",
                },
