    ["sys/net/pf_state"] = {
        ["custom"] = true,
        ["dynamic_vars"] = {
            "PF_STATUS",
            "PF_ANCHOR",
        },
        ["has_makefile"] = true,
        ["has_regress_targets_var"] = true,
        ["ldadd_libs"] = {},
        ["progs"] = {},
        ["srcs"] = {},
        ["targets"] = {
            ["check-setup"] = {
                ["recipe_lines"] = {},
            },
            ["check-setup-local"] = {
                ["recipe_lines"] = {
                    "@echo '\\n======== $@ ========'",
                    "ping -n -c 1 ${LOCAL_ADDR}",
                    "route -n get -inet ${LOCAL_ADDR} | grep -q 'flags: .*LOCAL'",
                    "ping -n -c 1 ${REMOTE_ADDR}",
                    "route -n get -inet ${REMOTE_ADDR} | fgrep -q 'interface: ${LOCAL_IF}'",
                    ".for ip in FAKE_NET FAKE_NET_ADDR",
                    "route -n get -inet ${${ip}} | grep -q 'flags: .*BLACKHOLE'",
                    ".endfor",
                },
            },
            ["check-setup-remote"] = {
                ["recipe_lines"] = {
                    "@echo '\\n======== $@ ========'",
                    "ssh ${REMOTE_SSH} ping -n -c 1 ${REMOTE_ADDR}",
                    "ssh ${REMOTE_SSH} route -n get -inet ${REMOTE_ADDR} | grep -q 'flags: .*LOCAL'",
                    "ssh ${REMOTE_SSH} ping -n -c 1 ${LOCAL_ADDR}",
                    ".for ip in FAKE_NET FAKE_NET_ADDR",
                    "ssh ${REMOTE_SSH} route -n get -inet ${${ip}} | fgrep -q 'gateway: ${LOCAL_ADDR}'",
                    ".endfor",
                    "ssh ${REMOTE_SSH} netstat -na -f inet -p tcp | fgrep ' *.7 '",
                    "ssh ${REMOTE_SSH} ${SUDO} pfctl -sr | grep '^anchor \"regress\" all$$'",
                    "ssh ${REMOTE_SSH} ${SUDO} pfctl -si | grep '^Status: Enabled '",
                },
            },
            ["cleanup"] = {
                ["recipe_lines"] = {
                    "${SUDO} pfctl -a regress -Fr",
                    "rm -f stamp-pfctl",
                },
            },
            ["regress"] = {
                ["recipe_lines"] = {
                    "@echo Install scapy package to run this regress.",
                    "@echo SKIPPED",
                    "PF_STATUS !=\9${SUDO} pfctl -si | sed -n 's/^Status: \\([^ ]*\\) .*/\\1/p'",
                    "PF_ANCHOR !=\9${SUDO} pfctl -sr | sed -n 's/^anchor \"\\([^\"]*\\)\" all$$/\\1/p'",
                    "@echo pf status: \"${PF_STATUS}\"",
                    "@echo pf anchor: \"${PF_ANCHOR}\"",
                    "@echo This test cannot run with pf filtering packets on localhost.",
                    "@echo Either disable pf or add a line 'anchor \"regress\"' to pf.conf.",
                    "@echo There the test will add a stateless rule that passes all packets.",
                    "@echo SKIPPED",
                    "@echo This tests needs a remote machine to operate on",
                    "@echo LOCAL_IF REMOTE_SSH LOCAL_ADDR REMOTE_ADDR FAKE_NET FAKE_NET_ADDR",
                    "@echo are empty.  Fill out these variables for additional tests.",
                    "@echo SKIPPED",
                    ".MAIN: all",
                    ".BEGIN:",
                    "${SUDO} true",
                    "ssh -t ${REMOTE_SSH} ${SUDO} true",
                    "rm -f stamp-pfctl",
                    "@echo",
                    "addr.py: Makefile",
                    "rm -f $@ $@.tmp",
                    "echo 'LOCAL_IF = \"${LOCAL_IF}\"' >>$@.tmp",
                    ".for var in LOCAL REMOTE FAKE_NET",
                    "echo '${var}_ADDR = \"${${var}_ADDR}\"' >>$@.tmp",
                    ".endfor",
                    "echo 'FAKE_NET = \"${FAKE_NET}\"' >>$@.tmp",
                    "mv $@.tmp $@",
                },
            },
            ["stamp-pfctl"] = {
                ["recipe_lines"] = {
                    "cat addr.py ${.CURDIR}/pf.conf | /sbin/pfctl -n -f -",
                    "cat addr.py ${.CURDIR}/pf.conf |  \9    ssh ${REMOTE_SSH} ${SUDO} pfctl -a regress -f -",
                    "echo 'pass on ${LOCAL_IF} no state' | ${SUDO} pfctl -a regress -f -",
                    "@date >$@",
                },
            },
        },
        ["unknown_includes"] = {
            "bsd.own.mk",
        },
    },
    ["sys/net/pf_table"] = {
        ["custom"] = true,
        ["dynamic_vars"] = {},
        ["has_makefile"] = true,
        ["has_regress_targets_var"] = true,
        ["ldadd_libs"] = {},
        ["progs"] = {},
        ["srcs"] = {},
        ["targets"] = {
            ["cleanup"] = {
                ["recipe_lines"] = {
                    "rm -f stamp-setup",
                    "${SUDO} pfctl -qt __regress_tbl -T kill",
                    "${SUDO} pfctl -q -a regress/ttest -Fr",
                    "${SUDO} pfctl -q -a regress/ttest -qt instance -T kill",
                },
            },
            ["flags"] = {
                ["recipe_lines"] = {
                    "@echo 'loading pf-reftab,conf (tables referenced by rules only)'",
                    "@cat pf-reftab.conf",
                    "${SUDO} pfctl -a regress/ttest -f pf-reftab.conf",
                    "@echo 'tables <reference> and <instance> should both have ----r--'",
                    "${SUDO} pfctl -a regress/ttest -sT -vg | diff table-ref.out -",
                    "@echo 'creating <instance> table on command line, flags should be:'",
                    "@cat table-persist.out",
                    "${SUDO} pfctl -a regress/ttest -t instance -T add 192.168.1.0/24",
                    "${SUDO} pfctl -a regress/ttest -sT -vg | diff table-persist.out -",
                    "@echo 'flushing rules'",
                    "${SUDO} pfctl -a regress/ttest -Fr",
                    "@echo 'table <reference> should be gone, table <instance> should stay'",
                    "${SUDO} pfctl -a regress/ttest -sT -vg | diff table-refgone.out -",
                    "@echo 'loading pf-instab.conf'",
                    "@cat pf-instab.conf",
                    "${SUDO} pfctl -a regress/ttest -f pf-instab.conf",
                    "@echo 'table <instance> loses -p- flag:'",
                    "@cat table-pgone.out",
                    "${SUDO} pfctl -a regress/ttest -sT -vg | diff table-pgone.out -",
                    "@echo 'flusing rules, both tables should be gone'",
                    "${SUDO} pfctl -a regress/ttest -Fr",
                    "@echo 'anchor regress/ttest must be gone'",
                    "${SUDO} pfctl -a regress/ttest -sr 2>&1 | grep 'pfctl: Anchor does not exist'",
                    ".PHONY: hit miss flags",
                },
            },
            ["hit"] = {
                ["recipe_lines"] = {
                    "for i in `cat ${.CURDIR}/table.hit`; do  \9\9echo -n \"hit $$i \";  \9\9${SUDO} pfctl -qt __regress_tbl -T test $$i || exit 1;  \9\9echo success;  \9done;  \9exit 0",
                },
            },
            ["miss"] = {
                ["recipe_lines"] = {
                    "for i in `cat ${.CURDIR}/table.miss`; do  \9\9echo -n \"miss $$i \";  \9\9${SUDO} pfctl -qt __regress_tbl -T test $$i && exit 1;  \9\9echo success;  \9done;  \9exit 0",
                    "pf-instab.conf:",
                    "@echo 'table <instance> { 192.168.1.0/24 }' > $@",
                    "@echo 'pass in from <instance> to <reference>' >> $@",
                    "pf-reftab.conf:",
                    "@echo 'pass in from <instance> to <reference>' > $@",
                    "table-pgone.out:",
                    "@echo '--a-r--\9instance@regress/ttest' > $@",
                    "@echo '----r--\9reference@regress/ttest' >> $@",
                    "table-persist.out:",
                    "@echo '-pa-r--\9instance@regress/ttest' > $@",
                    "@echo '----r--\9reference@regress/ttest' >> $@",
                    "table-ref.out:",
                    "@echo '----r--\9instance@regress/ttest' > $@",
                    "@echo '----r--\9reference@regress/ttest' >> $@",
                    "table-refgone.out:",
                    "@echo '-pa----\9instance@regress/ttest' > $@",
                },
            },
            ["stamp-setup"] = {
                ["recipe_lines"] = {
                    "${SUDO} pfctl -q -a regress/ttest -Fa || exit 0",
                    "${SUDO} pfctl -qt __regress_tbl -T add -f ${.CURDIR}/table.in",
                    "date >$@",
                },
            },
        },
        ["unknown_includes"] = {},
    },
