                    "ssh ${ECO_SSH} route -n get -${inet} ${${host}_${dir}_${ipv}} | \9    grep -q 'flags: .*LOCAL'",
                    ".endfor",
                    "ssh ${ECO_SSH} ${ping} -n -c 1 ${RT_OUT_${ipv}}",
                    ".for host dir in RT IN IPS OUT IPS IN SRC OUT",
                    "ssh ${ECO_SSH} route -n get -${inet} ${${host}_${dir}_${ipv}} | \9    fgrep -q 'gateway: ${RT_OUT_${ipv}}'",
                    ".endfor",
                    ".for sec in ESP AH IPIP IPCOMP BUNDLE",
                    ".for host mode in ECO TUNNEL4 ECO TUNNEL6",
                    "ssh ${ECO_SSH} ${ping} -n -c 1 ${${host}_${sec}_${mode}_${ipv}}",
                    "ssh ${ECO_SSH} route -n get -${inet} ${${host}_${sec}_${mode}_${ipv}} | \9    grep -q 'flags: .*LOCAL'",
                    ".endfor",
                    ".for host mode in SRC TUNNEL",
                    "ssh ${ECO_SSH} route -n get -${inet} ${${host}_${sec}_${mode}_${ipv}} | \9    fgrep -q 'gateway: ${RT_OUT_${ipv}}'",
                    ".endfor",
                    ".for host mode in ECO TUNNEL4 ECO TUNNEL6",
                    "ssh ${ECO_SSH} netstat -nav -f ${inet} -p udp | \9    fgrep ' ${${host}_${sec}_${mode}_${ipv}}.7 '",
