            ["stamp-bpf"] = {
                ["recipe_lines"] = {
                    "rm -f enc0.tcpdump",
                    "-ssh ${IPS_SSH} ${SUDO} pkill -f \"'^${DUMPCMD} enc0'\" || true",
                    "ssh -f ${IPS_SSH} ${SUDO} ${DUMPCMD} enc0 -w ${.OBJDIR}/enc0.pcap",
                    "sleep 5",
