                    "@date >$@",
                },
            },
            ["stamp-drop"] = {
                ["recipe_lines"] = {
                    "netstat -nv -p tcp | \9    perl -ne ' \9\9/ ${PREFIX_IPV6}.* ${PREFIX_IPV6}/ || \9\9/ ${PREFIX_IPV4}.* ${PREFIX_IPV4}/ or next; \9\9my ($$laddr,$$faddr) = (split)[3,4]; \9\9my ($$lip,$$lport) = $$laddr =~ /(.*)\\.(\\d+)/; \9\9my ($$fip,$$fport) = $$faddr =~ /(.*)\\.(\\d+)/; \9\9print join(\" \",$$lip,$$lport,$$fip,$$fport),\"\\n\"' | \9    xargs -r -L1 ${SUDO} tcpdrop",
                    "@date >$@",
                    "run-pflog-ping-IPS_AH_TRANSP_IPV4      run-pflog-udp-IPS_AH_TRANSP_IPV4      run-pflog-tcp-IPS_AH_TRANSP_IPV4      run-pflog-nonxt-IPS_AH_TRANSP_IPV4      run-pflog-ping-IPS_AH_TRANSP_IPV6      run-pflog-udp-IPS_AH_TRANSP_IPV6      run-pflog-tcp-IPS_AH_TRANSP_IPV6      run-pflog-nonxt-IPS_AH_TRANSP_IPV6:",
                    "@echo DISABLED",
                    ".for host dir in SRC OUT IPS IN IPS OUT RT IN RT OUT ECO IN",
                    ".for ping ipv in ping IPV4 ping6 IPV6",
                },
            },
            ["stamp-hostname"] = {
                ["recipe_lines"] = {
                    "${SUDO} sh -c \"umask 027; \9    { sed '/^",
                    "${SUDO} sh -c \"mv /etc/hostname.${SRC_OUT_IF}.tmp \9    /etc/hostname.${SRC_OUT_IF} && \9    sh /etc/netstart ${SRC_OUT_IF}\"",
                    ".for host dir in IPS IN IPS OUT RT IN RT OUT ECO IN",
                    "ssh root@${${host}_SSH} \"umask 027; \9    { sed '/^",
                    "ssh root@${${host}_SSH} \"mv /etc/hostname.${${host}_${dir}_IF}.tmp \9    /etc/hostname.${${host}_${dir}_IF} && \9    sh /etc/netstart ${${host}_${dir}_IF}\"",
                    ".endfor",
                    "date >$@",
                    ".for host in IPS ECO",
                    "${${host}_SSH}/inetd.conf: Makefile",
                    "mkdir -p ${@:H}",
                    "rm -f $@ $@.tmp",
                    "echo '",
                    "echo echo stream tcp nowait root internal >>$@.tmp",
                    "echo echo stream tcp6 nowait root internal >>$@.tmp",
                    ".for sec in ESP AH IPIP IPCOMP BUNDLE",
                    ".for mode in TRANSP TUNNEL4 TUNNEL6",
                    "echo '${${host}_${sec}_${mode}_IPV4}:echo' \9    dgram udp wait root internal >>$@.tmp",
                    "echo '[${${host}_${sec}_${mode}_IPV6}]:echo' \9    dgram udp6 wait root internal >>$@.tmp",
                    ".endfor",
                    ".endfor",
                    "mv $@.tmp $@",
                    ".endfor",
                },
            },
            ["stamp-inetd"] = {
                ["recipe_lines"] = {
                    ".for host in IPS ECO",
                    "ssh root@${${host}_SSH} \"umask 022; \9    { sed '/^",
                    "ssh root@${${host}_SSH} \"mv /etc/inetd.conf.tmp /etc/inetd.conf && \9    rcctl enable inetd && rcctl restart inetd\"",
                    ".endfor",
                    "date >$@",
                    ".for host in IPS ECO",
                    "${${host}_SSH}/nonxt_reflect: nonxt_reflect.sh Makefile",
                    "mkdir -p ${@:H}",
                    "rm -f $@ $@.tmp",
                    "echo '",
                    "echo '",
                    "echo 'local_addresses=\"' >>$@.tmp",
                    ".for sec in ESP AH IPIP IPCOMP BUNDLE",
                    ".for mode in TRANSP TUNNEL4 TUNNEL6",
                    ".for ipv in IPV4 IPV6",
                    "echo '${${host}_${sec}_${mode}_${ipv}}' >>$@.tmp",
                    ".endfor",
                    ".endfor",
                    ".endfor",
                    "echo '\"' >>$@.tmp",
                    "cat ${.CURDIR}/nonxt_reflect.sh >>$@.tmp",
                    "sh -n $@.tmp",
                    "chmod 755 $@.tmp",
                    "mv $@.tmp $@",
                    ".endfor",
                },
            },
            ["stamp-ipsec"] = {
                ["recipe_lines"] = {},
            },
            ["stamp-nonxt-reflect"] = {
                ["recipe_lines"] = {
                    ".for host in IPS ECO",
                    "ssh ${${host}_SSH} make -C ${.CURDIR} nonxt-reflect",
                    "scp ${${host}_SSH}/nonxt_reflect root@${${host}_SSH}:/etc/rc.d/",
                    "ssh root@${${host}_SSH} \9    \"rcctl enable nonxt_reflect && rcctl restart nonxt_reflect\"",
                    ".endfor",
                    "date >$@",
                    ".PHONY: check-setup",
                },
            },
            ["stamp-pfctl"] = {
                ["recipe_lines"] = {},
            },
            ["stamp-pflog"] = {
                ["recipe_lines"] = {
                    "rm -f pflog0.tcpdump",
                    "-ssh ${IPS_SSH} ${SUDO} pkill -f \"'^${DUMPCMD} pflog0'\" || true",
