                    "sleep 5",
                    "rm -f stamp-stop",
                    "@date >$@",
                },
            },
            ["stamp-reflect"] = {
                ["recipe_lines"] = {},
            },
            ["stamp-stop"] = {
                ["recipe_lines"] = {
                    "sleep 5",
                    "-ssh ${IPS_SSH} ${SUDO} pkill -f \"'^${DUMPCMD}'\"",
                    ".for i in enc0 pflog0",
                    "ssh ${IPS_SSH} cat ${.OBJDIR}/$i.pcap | tcpdump -evvvnr - >$i.tcpdump",
                    ".endfor",
                    "@date >$@",
                },
