                ["recipe_lines"] = {},
            },
            ["check-setup-local"] = {
                ["recipe_lines"] = {
                    "@echo '\\n======== $@ ========'",
                    "ping -n -c 1 ${LOCAL_ADDR}",
                    "route -n get -inet ${LOCAL_ADDR} | grep -q 'flags: .*LOCAL'",
                    "arp -na | grep -q '^${LOCAL_ADDR} * ${LOCAL_MAC} * ${LOCAL_IF} permanent'",
                    "ping -n -c 1 ${REMOTE_ADDR}",
                    "route -n get -inet ${REMOTE_ADDR} | fgrep -q 'interface: ${LOCAL_IF}'",
                    "route -n get -inet ${FAKE_NET_ADDR} | grep -q 'flags: .*BLACKHOLE'",
                    "route -n get -inet -net ${FAKE_NET} | grep -q 'flags: .*BLACKHOLE'",
                    "ping6 -n -c 1 ${LOCAL_ADDR6}",
                    "route -n get -inet6 ${LOCAL_ADDR6} | grep -q 'flags: .*LOCAL'",
                    "ndp -na | grep -q '^${LOCAL_ADDR6} * ${LOCAL_MAC} * ${LOCAL_IF} permanent'",
                    "ping6 -n -c 1 ${REMOTE_ADDR6}",
                    "route -n get -inet6 ${REMOTE_ADDR6} | fgrep -q 'interface: ${LOCAL_IF}'",
                    "route -n get -inet6 ${FAKE_NET_ADDR6} | grep -q 'flags: .*BLACKHOLE'",
                    "route -n get -inet6 -net ${FAKE_NET6} | grep -q 'flags: .*BLACKHOLE'",
                    "${SUDO} pfctl -sr | grep '^anchor \"regress\" all$$'",
                    "${SUDO} pfctl -si | grep '^Status: Enabled '",
                },
            },
            ["check-setup-remote"] = {
                ["recipe_lines"] = {
                    "@echo '\\n======== $@ ========'",
                    "ssh ${REMOTE_SSH} ping -n -c 1 ${REMOTE_ADDR}",
                    "ssh ${REMOTE_SSH} route -n get -inet ${REMOTE_ADDR} | grep -q 'flags: .*LOCAL'",
                    "ssh ${REMOTE_SSH} arp -na | grep -q '^${REMOTE_ADDR} * ${REMOTE_MAC} * .* permanent'",
                    "ssh ${REMOTE_SSH} ping -n -c 1 ${LOCAL_ADDR}",
                    ".for ip in FAKE_NET FAKE_NET_ADDR",
                    "ssh ${REMOTE_SSH} route -n get -inet ${${ip}} | fgrep -q 'gateway: ${LOCAL_ADDR}'",
                    ".endfor",
                    "ssh ${REMOTE_SSH} ping6 -n -c 1 ${REMOTE_ADDR6}",
                    "ssh ${REMOTE_SSH} route -n get -inet6 ${REMOTE_ADDR6} | grep -q 'flags: .*LOCAL'",
                    "ssh ${REMOTE_SSH} ndp -na | grep -q '^${REMOTE_ADDR6} * ${REMOTE_MAC} * .* permanent'",
                    "ssh ${REMOTE_SSH} ping6 -n -c 1 ${LOCAL_ADDR6}",
                    ".for ip in FAKE_NET6 FAKE_NET_ADDR6",
                    "ssh ${REMOTE_SSH} route -n get -inet6 ${${ip}} | fgrep -q 'gateway: ${LOCAL_ADDR6}'",
                    ".endfor",
                    ".for af in inet inet6",
                    "ssh ${REMOTE_SSH} netstat -na -f ${af} -p tcp | fgrep ' *.19 '",
                    ".endfor",
                    "ssh ${REMOTE_SSH} netstat -na -f inet6 -p udp | fgrep ' *.7 '",
                    "ssh ${REMOTE_SSH} ${SUDO} pfctl -sr | grep '^anchor \"regress\" all$$'",
                    "ssh ${REMOTE_SSH} ${SUDO} pfctl -si | grep '^Status: Enabled '",
                },
            },
