                    "for  i in `jot 100`; do \9    if fgrep -q Listening server.log; then break; fi; sleep .1; done",
                    "fgrep Listening server.log",
                    "echo bar |  \9    ktrace -f /mnt/regress-nfs-client/netcat-client.ktrace  \9    nc -n -v -N 127.0.0.1  \9    `sed -n 's/Listening on 127.0.0.1 //p' server.log` 2>client.log",
                    "fgrep Connection client.log",
                    "kdump -f /mnt/regress-nfs-client/netcat-server.ktrace | \9    fgrep 'nc       CALL  exit(0)'",
