        ["targets"] = {
            ["run-regress-fuzz"] = {
                ["recipe_lines"] = {
                    "@echo \"\\n==== $@ ====\"",
                    "gzip </etc/rc >rc.gz",
                    ".for i in ${JOT100}",
                    "dd if=rc.gz bs=1k of=fuzz.gz status=none",
                },
            },
            ["run-regress-gunzip"] = {
                ["recipe_lines"] = {
                    "@echo \"\\n==== $@ ====\"",
                    "gzip -v </etc/rc >rc.gz",
                    "gunzip -f rc.gz",
                    "diff -up /etc/rc rc",
                },
            },
            ["run-regress-integrity"] = {
                ["recipe_lines"] = {
                    "@echo \"\\n==== $@ ====\"",
                    "gzip -v </etc/rc >rc.gz",
                    "gzip -vt rc.gz",
                },
            },
            ["run-regress-multi"] = {
                ["recipe_lines"] = {
                    "@echo \"\\n==== $@ ====\"",
                    "gzip -c /etc/rc /etc/motd >multi.gz",
                    "gzip -vt multi.gz",
                    "gunzip -f multi.gz",
                    "cat /etc/rc /etc/motd >rcmotd",
                    "diff -up rcmotd multi",
                },
            },
            ["run-regress-name"] = {
                ["recipe_lines"] = {
                    "@echo \"\\n==== $@ ====\"",
                    "gzip -c /etc/rc >in.gz",
                    "rm -f rc",
                    "gunzip -N in.gz",
                    "diff -up /etc/rc rc",
                    "gzip -c /etc/rc >in.gz",
                    "gzip -lN in.gz | grep -q ' rc$$'",
                    "gzip -lN <in.gz | grep -q ' rc$$'",
                    "rm -f out",
                    "gzip -dN <in.gz >out",
                    "diff -up /etc/rc out",
                    "rm -f out",
                    "zcat -N in.gz >out",
                    "diff -up /etc/rc out",
                },
            },
            ["run-regress-owner-unzip"] = {
                ["recipe_lines"] = {
                    "@echo \"\\n==== $@ ====\"",
                    "rm -f owner.gz",
                    "gzip </etc/rc >owner.gz",
                    "${SUDO} chown nobody:nobody owner.gz",
                    "rm -f owner",
                    "${SUDO} gunzip owner.gz",
                    "ls -l owner | grep ' nobody  *nobody '",
                },
            },
            ["run-regress-owner-zip"] = {
                ["recipe_lines"] = {
                    "@echo \"\\n==== $@ ====\"",
                    "rm -f owner",
                    "cat /etc/rc >owner",
                    "${SUDO} chown nobody:nobody owner",
                    "rm -f owner.gz",
                    "${SUDO} gzip owner",
                    "ls -l owner.gz | grep ' nobody  *nobody '",
                },
            },
            ["run-regress-perm-unzip"] = {
                ["recipe_lines"] = {
                    "@echo \"\\n==== $@ ====\"",
                    "gzip </etc/rc >perm.gz",
                    "chmod 614 perm.gz",
                    "rm -f perm",
                    "gunzip perm.gz",
                    "ls -l perm | grep '^-rw---xr-- '",
                },
            },
            ["run-regress-perm-zip"] = {
                ["recipe_lines"] = {
                    "@echo \"\\n==== $@ ====\"",
                    "cat /etc/rc >perm",
                    "chmod 614 perm",
                    "rm -f perm.gz",
