    ["usr.bin/ssh"] = {
        ["custom"] = true,
        ["dynamic_vars"] = {
            "USERNAME",
        },
        ["has_makefile"] = true,
        ["has_regress_targets_var"] = true,
        ["ldadd_libs"] = {},
        ["progs"] = {},
        ["srcs"] = {},
        ["targets"] = {
            ["clean"] = {
                ["recipe_lines"] = {
                    "rm -f ${CLEANFILES}",
                    "rm -rf .putty",
                    "rm -rf .dropbear",
                    "rm -rf .fakehome",
                },
            },
            ["extra"] = {
                ["recipe_lines"] = {
                    ".for s in ${SUBDIR}",
                },
            },
            ["interop"] = {
                ["recipe_lines"] = {
                    ".for t in ${EXTRA_TESTS}",
                },
            },
            ["modpipe"] = {
                ["recipe_lines"] = {},
            },
            ["t-integrity"] = {
                ["recipe_lines"] = {
                    ".for t in ${LTESTS} ${INTEROP_TESTS} ${EXTRA_TESTS}",
                    "t-${t}: timestamp",
                    "env SUDO=\"${SUDO}\" ${TEST_ENV}  \9    sh ${.CURDIR}/test-exec.sh ${.OBJDIR} ${.CURDIR}/${t}.sh",
                    ".endfor",
                    ".undef LTESTS_STARTED",
                    ".for t in ${LTESTS}",
                },
            },
            ["t1"] = {
                ["recipe_lines"] = {
                    "ssh-keygen -if ${.CURDIR}/rsa_ssh2.prv | diff - ${.CURDIR}/rsa_openssh.prv",
                    "tr '\\n' '\\r' <${.CURDIR}/rsa_ssh2.prv > ${.OBJDIR}/rsa_ssh2_cr.prv",
                    "ssh-keygen -if ${.OBJDIR}/rsa_ssh2_cr.prv | diff - ${.CURDIR}/rsa_openssh.prv",
                    "awk '{print $$0 \"\\r\"}' ${.CURDIR}/rsa_ssh2.prv > ${.OBJDIR}/rsa_ssh2_crnl.prv",
                    "ssh-keygen -if ${.OBJDIR}/rsa_ssh2_crnl.prv | diff - ${.CURDIR}/rsa_openssh.prv",
                },
            },
            ["t10"] = {
                ["recipe_lines"] = {
                    "ssh-keygen -lf t10.out > /dev/null",
                    "ssh-keygen -Bf t10.out > /dev/null",
                },
            },
            ["t11"] = {
                ["recipe_lines"] = {
                    "ssh-keygen -E sha256 -lf ${.CURDIR}/rsa_openssh.pub | \9\9awk '{print $$2}' | diff - ${.CURDIR}/t11.ok",
                    "t12.out:",
                    "ssh-keygen -q -t ed25519 -N '' -C 'test-comment-1234' -f $@",
                },
            },
            ["t12"] = {
                ["recipe_lines"] = {
                    "ssh-keygen -lf t12.out.pub | grep -q test-comment-1234",
                },
            },
            ["t2"] = {
                ["recipe_lines"] = {
                    "cat ${.CURDIR}/rsa_openssh.prv > t2.out",
                    "chmod 600 t2.out",
                    "ssh-keygen -yf t2.out | diff - ${.CURDIR}/rsa_openssh.pub",
                },
            },
            ["t3"] = {
                ["recipe_lines"] = {
                    "ssh-keygen -ef ${.CURDIR}/rsa_openssh.pub | \9\9ssh-keygen -if /dev/stdin | \9\9diff - ${.CURDIR}/rsa_openssh.pub",
                },
            },
            ["t4"] = {
                ["recipe_lines"] = {
                    "ssh-keygen -E md5 -lf ${.CURDIR}/rsa_openssh.pub | \9\9awk '{print $$2}' | diff - ${.CURDIR}/t4.ok",
                },
            },
            ["t5"] = {
                ["recipe_lines"] = {
                    "ssh-keygen -Bf ${.CURDIR}/rsa_openssh.pub | \9\9awk '{print $$2}' | diff - ${.CURDIR}/t5.ok",
                    "t7.out:",
                    "ssh-keygen -q -t rsa -N '' -f $@ ;",
                },
            },
            ["t7"] = {
                ["recipe_lines"] = {
                    "ssh-keygen -lf t7.out > /dev/null",
                    "ssh-keygen -Bf t7.out > /dev/null",
                    "t9.out:",
                    "ssh-keygen -q -t ecdsa -N '' -f $@",
                },
            },
            ["t9"] = {
                ["recipe_lines"] = {
                    "ssh-keygen -lf t9.out > /dev/null",
                    "ssh-keygen -Bf t9.out > /dev/null",
                    "t10.out:",
                    "ssh-keygen -q -t ed25519 -N '' -f $@",
                },
            },
            ["timestamp"] = {
                ["recipe_lines"] = {},
            },
        },
        ["unknown_includes"] = {},
    },
