    ["usr.sbin/acme-client"] = {
        ["custom"] = true,
        ["dynamic_vars"] = {},
        ["has_makefile"] = true,
        ["has_regress_targets_var"] = true,
        ["ldadd_libs"] = {},
        ["progs"] = {},
        ["srcs"] = {},
        ["targets"] = {
            ["clean"] = {
                ["recipe_lines"] = {
                    "rm -f a.out [Ee]rrs mklog *.core y.tab.h ktrace.out pebble-config.json",
                    "rm -f pebble.out",
                    "rm -rf etc www",
                    "etc/acme-client.conf: acme-client.conf",
                    "mkdir -p etc",
                    "sed 's,$${.OBJDIR},${.OBJDIR},' \9\9${.CURDIR}/acme-client.conf > etc/acme-client.conf",
                    "etc/acme-client-profile.conf: acme-client-profile.conf",
                    "mkdir -p etc",
                    "sed 's,$${.OBJDIR},${.OBJDIR},' \9\9${.CURDIR}/acme-client-profile.conf  \9\9> etc/acme-client-profile.conf",
                    "etc/acme-client-ipaddress.conf: acme-client-ipaddress.conf",
                    "mkdir -p etc",
                    "sed 's,$${.OBJDIR},${.OBJDIR},' \9\9${.CURDIR}/acme-client-ipaddress.conf  \9\9> etc/acme-client-ipaddress.conf",
                    "etc/httpd.conf: httpd.conf",
                    "mkdir -p etc",
                    "sed 's,$${.OBJDIR},${.OBJDIR},' \9\9${.CURDIR}/httpd.conf >etc/httpd.conf",
                    "mkdir -p www/htdocs www/acme www/logs etc/acme etc/ssl/acme/private",
                },
            },
            ["httpd-start"] = {
                ["recipe_lines"] = {
                    "${SUDO} /usr/sbin/httpd -f ${.OBJDIR}/etc/httpd.conf",
                    "sleep .1",
                    "pgrep -xf \"/usr/sbin/httpd -f ${.OBJDIR}/etc/httpd.conf\"",
                },
            },
            ["httpd-stop"] = {
                ["recipe_lines"] = {
                    "-${SUDO} pkill -xf \"/usr/sbin/httpd -f ${.OBJDIR}/etc/httpd.conf\"",
                    "pebble-config.json:",
                    "sed 's,$${.CURDIR},${.CURDIR},' \9\9${.CURDIR}/pebble-config.json > pebble-config.json",
                },
            },
            ["pebble-start"] = {
                ["recipe_lines"] = {
                    "/usr/local/bin/pebble -config ${.OBJDIR}/pebble-config.json >  \9    ${.OBJDIR}/pebble.out &",
                    "while ! $$(fgrep -q 'Root CA certificate available'  \9    ${.OBJDIR}/pebble.out); do sleep .1; done",
                },
            },
            ["pebble-stop"] = {
                ["recipe_lines"] = {
                    "pkill -xf \"/usr/local/bin/pebble -config ${.OBJDIR}/pebble-config.json\"",
                },
            },
            ["regress"] = {
                ["recipe_lines"] = {
                    "@echo Install pebble package to run this regress.",
                    "@echo SKIPPED",
                },
            },
            ["run-regress-acme"] = {
                ["recipe_lines"] = {
                    "${SUDO} /usr/sbin/acme-client  \9    -f ${.OBJDIR}/etc/acme-client.conf  \9    -v localhost",
                    "${SUDO} /usr/sbin/acme-client  \9    -f ${.OBJDIR}/etc/acme-client.conf  \9    -r -v localhost",
                },
            },
            ["run-regress-acme-ipaddress"] = {
                ["recipe_lines"] = {
                    "${SUDO} /usr/sbin/acme-client  \9    -f ${.OBJDIR}/etc/acme-client-ipaddress.conf  \9    -v localhost",
                    "${SUDO} /usr/sbin/acme-client  \9    -f ${.OBJDIR}/etc/acme-client-ipaddress.conf  \9    -r -v localhost",
                },
            },
            ["run-regress-acme-ipaddress2"] = {
                ["recipe_lines"] = {
                    "${SUDO} /usr/sbin/acme-client  \9    -f ${.OBJDIR}/etc/acme-client-ipaddress.conf  \9    -v ::1",
                    "${SUDO} /usr/sbin/acme-client  \9    -f ${.OBJDIR}/etc/acme-client-ipaddress.conf  \9    -r -v ::1",
                },
            },
            ["run-regress-acme-profile"] = {
                ["recipe_lines"] = {
                    "${SUDO} /usr/sbin/acme-client  \9    -f ${.OBJDIR}/etc/acme-client-profile.conf  \9    -v localhost",
                    "${SUDO} /usr/sbin/acme-client  \9    -f ${.OBJDIR}/etc/acme-client-profile.conf  \9    -r -v localhost",
                },
            },
            ["run-regress-cleanup"] = {
                ["recipe_lines"] = {
                    "${.MAKE} -C ${.CURDIR} httpd-stop",
                    "${.MAKE} -C ${.CURDIR} pebble-stop",
                    ".PHONY: ${REGRESS_TARGETS} httpd-start httpd-stop pebble-start pebble-stop",
                },
            },
        },
        ["unknown_includes"] = {},
    },
